function assessments_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('assessments');
	if(!$arrPerm['insert']) return false;

	$data = [
		'class' => Request::lookup('class', ''),
		'total_marks' => Request::val('total_marks', ''),
		'teacher' => Request::lookup('teacher', ''),
		'subject' => Request::lookup('subject', ''),
		'avg_performance' => Request::val('avg_performance', ''),
		'highest_mark' => Request::val('highest_mark', ''),
		'lowest_mark' => Request::val('lowest_mark', ''),
		'date' => Request::dateComponents('date', '1'),
	];


	// hook: assessments_before_insert
	if(function_exists('assessments_before_insert')) {
		$args = [];
		if(!assessments_before_insert($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$error = '';
	// set empty fields to NULL
	$data = array_map(function($v) { return ($v === '' ? NULL : $v); }, $data);
	insert('assessments', backtick_keys_once($data), $error);
	if($error) {
		$error_message = $error;
		return false;
	}

	$recID = db_insert_id(db_link());

	update_calc_fields('assessments', $recID, calculated_fields()['assessments']);

	// hook: assessments_after_insert
	if(function_exists('assessments_after_insert')) {
		$res = sql("SELECT * FROM `assessments` WHERE `id`='" . makeSafe($recID, false) . "' LIMIT 1", $eo);
		if($row = db_fetch_assoc($res)) {
			$data = array_map('makeSafe', $row);
		}
		$data['selectedID'] = makeSafe($recID, false);
		$args = [];
		if(!assessments_after_insert($data, getMemberInfo(), $args)) { return $recID; }
	}

	// mm: save ownership data
	set_record_owner('assessments', $recID, getLoggedMemberID());

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID'))) assessments_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function assessments_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);

	// launch requests, asynchronously
	curl_batch($requests);
}

function assessments_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('assessments', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: assessments_before_delete
	if(function_exists('assessments_before_delete')) {
		$args = [];
		if(!assessments_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: '' 
			);
	}

	// child table: results
	$res = sql("SELECT `id` FROM `assessments` WHERE `id`='{$selected_id}'", $eo);
	$id = db_fetch_row($res);
	$rires = sql("SELECT COUNT(1) FROM `results` WHERE `assess`='" . makeSafe($id[0]) . "'", $eo);
	$rirow = db_fetch_row($rires);
	if($rirow[0] && !$AllowDeleteOfParents && !$skipChecks) {
		$RetMsg = $Translation["couldn't delete"];
		$RetMsg = str_replace('<RelatedRecords>', $rirow[0], $RetMsg);
		$RetMsg = str_replace('<TableName>', 'results', $RetMsg);
		return $RetMsg;
	} elseif($rirow[0] && $AllowDeleteOfParents && !$skipChecks) {
		$RetMsg = $Translation['confirm delete'];
		$RetMsg = str_replace('<RelatedRecords>', $rirow[0], $RetMsg);
		$RetMsg = str_replace('<TableName>', 'results', $RetMsg);
		$RetMsg = str_replace('<Delete>', '<input type="button" class="btn btn-danger" value="' . html_attr($Translation['yes']) . '" onClick="window.location = \'assessments_view.php?SelectedID=' . urlencode($selected_id) . '&delete_x=1&confirmed=1&csrf_token=' . urlencode(csrf_token(false, true)) . '\';">', $RetMsg);
		$RetMsg = str_replace('<Cancel>', '<input type="button" class="btn btn-success" value="' . html_attr($Translation[ 'no']) . '" onClick="window.location = \'assessments_view.php?SelectedID=' . urlencode($selected_id) . '\';">', $RetMsg);
		return $RetMsg;
	}

	sql("DELETE FROM `assessments` WHERE `id`='{$selected_id}'", $eo);

	// hook: assessments_after_delete
	if(function_exists('assessments_after_delete')) {
		$args = [];
		assessments_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='assessments' AND `pkValue`='{$selected_id}'", $eo);
}

function assessments_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('assessments', $selected_id, 'edit')) return false;

	$data = [
		'class' => Request::lookup('class', ''),
		'total_marks' => Request::val('total_marks', ''),
		'teacher' => Request::lookup('teacher', ''),
		'subject' => Request::lookup('subject', ''),
		'avg_performance' => Request::val('avg_performance', ''),
		'highest_mark' => Request::val('highest_mark', ''),
		'lowest_mark' => Request::val('lowest_mark', ''),
		'date' => Request::dateComponents('date', ''),
	];

	// get existing values
	$old_data = getRecord('assessments', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: assessments_before_update
	if(function_exists('assessments_before_update')) {
		$args = ['old_data' => $old_data];
		if(!assessments_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'assessments', 
		backtick_keys_once($set), 
		['`id`' => $selected_id], 
		$error_message
	)) {
		echo $error_message;
		echo '<a href="assessments_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	$eo = ['silentErrors' => true];

	update_calc_fields('assessments', $data['selectedID'], calculated_fields()['assessments']);

	// hook: assessments_after_update
	if(function_exists('assessments_after_update')) {
		$res = sql("SELECT * FROM `assessments` WHERE `id`='{$data['selectedID']}' LIMIT 1", $eo);
		if($row = db_fetch_assoc($res)) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['id'];
		$args = ['old_data' => $old_data];
		if(!assessments_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update ownership data
	sql("UPDATE `membership_userrecords` SET `dateUpdated`='" . time() . "' WHERE `tableName`='assessments' AND `pkValue`='" . makeSafe($selected_id) . "'", $eo);
}

